const fetch = require('node-fetch');

const { DATABASE_URL, ANTHROPIC_API_KEY, STRIPE_SECRET_KEY } = process.env;

// Test PostgreSQL
async function testDatabaseConnection() {
  if (!DATABASE_URL) {
    console.error('DATABASE_URL not set');
    return;
  }
  const client = new Client({ connectionString: DATABASE_URL });
  try {
    await client.connect();
    console.log('✅ Successfully connected to PostgreSQL');
    await client.end();
  } catch (error) {
    console.error('❌ PostgreSQL connection failed:', error.message);
  }
}

// Test Anthropic API
async function testAnthropicAPI() {
  if (!ANTHROPIC_API_KEY) {
    console.error('ANTHROPIC_API_KEY not set');
    return;
  }
  try {
    const res = await fetch('https://api.anthropic.com/v1/complete', {
      method: 'POST',
      headers: {
        'x-api-key': ANTHROPIC_API_KEY,
        'Content-Type': 'application/json',
      },
      body: JSON.stringify({ prompt: 'Hello', model: 'claude-2', max_tokens_to_sample: 100 })
    });

    if (res.status === 200) {
      console.log('✅ Anthropic API responded successfully');
    } else {
      console.error('❌ Anthropic API request failed:', res.statusText);
    }
  } catch (error) {
    console.error('❌ Anthropic API request error:', error.message);
  }
}

// Test Stripe API
async function testStripeAPI() {
  if (!STRIPE_SECRET_KEY) {
    console.error('STRIPE_SECRET_KEY not set');
    return;
  }
  try {
    const res = await fetch('https://api.stripe.com/v1/charges', {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${STRIPE_SECRET_KEY}`
      }
    });

    if (res.status === 200) {
      console.log('✅ Stripe API responded successfully');
    } else {
      console.error('❌ Stripe API request failed:', res.statusText);
    }
  } catch (error) {
    console.error('❌ Stripe API request error:', error.message);
  }
}

// Execute tests
async function runTests() {
  await testDatabaseConnection();
  await testAnthropicAPI();
  await testStripeAPI();
}

runTests();

