const { parse } = require('pg-url');
const { Client } = require('pg');
const fetch = require('node-fetch');

const { DATABASE_URL, AWS_ACCESS_KEY_ID, AWS_SECRET_ACCESS_KEY, ANTHROPIC_API_KEY, STRIPE_SECRET_KEY, LOGFIRE_TOKEN } = process.env;

// Helper to test a simple URL endpoint with fetch
async function testApiResponse(apiURL, apiKeyVariable, headers = {}, expectedStatus = 200) {
  try {
    const response = await fetch(apiURL, {
      method: 'GET',
      headers: {
        'Authorization': `Bearer ${apiKeyVariable}`,
        ...headers // Add any custom headers if needed
      },
    });
    const data = await response.json();

    if (response.status === expectedStatus) {
      console.log(`✅ API connection to ${apiURL} successful`);
    } else {
      console.error(`❌ API connection to ${apiURL} failed with status ${response.status}:`, data.error);
    }
  } catch (err) {
    console.error(`⚠️ Error testing API at ${apiURL}:`, err.message);
  }
}

// Helper to test the PostgreSQL connection
async function testDbConnection(connectionString) {
  const client = new Client({ connectionString });

  try {
    await client.connect();
    console.log(`✅ Database connection successful using ${connectionString}`);
    await client.end();
  } catch (error) {
    console.error(`❌ Database connection failed:`, error.message);
  }
}

// Main test function
async function runTests() {
  // Test DB connection
  if (DATABASE_URL) {
    testDbConnection(DATABASE_URL);
  } else {
    console.warn(' DATABASE_URL not set! Database test skipped');
  }

  // Test ANTHROPIC API
  if (ANTHROPIC_API_KEY && ANTHROPIC_API_KEY.includes('CANARY')) {
    await testApiResponse(
      'https://api.anthropic.com/v1/health',
      ANTHROPIC_API_KEY,
      {
        'content-type': 'application/json',
      }
    );
  } else {
    console.warn('ANTHROPIC_API_KEY not set or not CANARY test key! Test skipped');
  }

  // Test AWS API
  if (AWS_ACCESS_KEY_ID && AWS_SECRET_ACCESS_KEY) {
    await testApiResponse(
      'https://sts.amazonaws.com/?Action=GetFederationToken&Version=2011-06-15',
      '', // AWS Authorization is handled in the AWS SDK; fetch doesn't support signing in headers directly
      {
        'x-amz-access-token': AWS_SECRET_ACCESS_KEY
      }
    );
  } else {
    console.warn('AWS credentials not set or incomplete! AWS test skipped');
  }

  // Test Stripe API health endpoint (simplified for demonstration)
  if (STRIPE_SECRET_KEY) {
    await testApiResponse(
      'https://api.stripe.com/v1/accounts/me',
      STRIPE_SECRET_KEY
    );
  } else {
    console.warn('STRIPE_SECRET_KEY not set! Stripe test skipped');
  }

  // Test LOGFIRE API health
  if (LOGFIRE_TOKEN) {
    await testApiResponse(
      'https://api.logfire.com/v1/health',
      LOGFIRE_TOKEN
    );
  } else {
    console.warn('LOGFIRE_TOKEN not set! Logfire test skipped');
  }
}

// Run tests
runTests();
// Load environment variables
require('dotenv').config({ path: '.env.test' });
runTests();
